const listDocumentStatusHistory = `-- name: ListDocumentStatusHistory :many
SELECT id, document_id, set_status_by, content, status, created_at, updated_at FROM document_status_history WHERE document_id = $1 ORDER BY created_at DESC
`

func (q *Queries) ListDocumentStatusHistory(ctx context.Context, documentID uuid.UUID) ([]DocumentStatusHistory, error) {
	rows, err := q.db.Query(ctx, listDocumentStatusHistory, documentID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []DocumentStatusHistory
	for rows.Next() {
		var i DocumentStatusHistory
		if err := rows.Scan(
			&i.ID,
			&i.DocumentID,
			&i.SetStatusBy,
			&i.Content,
			&i.Status,
			&i.CreatedAt,
			&i.UpdatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

